{
  "query": "query SalesNavRecords($filters: SalesNavigatorFilterInput) { salesNavigator { salesNavigatorRecords(filters: $filters) { items { id userId timestamp version source createdAt } pageInfo { total limit offset hasNext hasPrevious } } } } }",
  "variables": {
    "filters": {
      "limit": 50,
      "offset": 0
    }
  }
}

{
  "query": "mutation SaveSalesNav($input: SaveProfilesInput!) { salesNavigator { saveSalesNavigatorProfiles(input: $input) { success savedCount failedCount } } } }",
  "variables": {
    "input": {
      "profiles": []
    }
  }
}
